/* Nav: multiple dropdowns + hamburger (mobile) + auto-hide on scroll (UI only) */
(() => {
  const header = document.querySelector('.header');
  if (!header) return;

  const nav = header.querySelector('.nav');
  const navToggle = header.querySelector('.nav-toggle');
  const dropdowns = Array.from(header.querySelectorAll('.dropdown'));

  const closeDropdowns = (except = null) => {
    dropdowns.forEach((dropdown) => {
      if (dropdown === except) return;
      dropdown.classList.remove('open');
      const toggle = dropdown.querySelector('.nav-dropdown');
      if (toggle) toggle.setAttribute('aria-expanded', 'false');
    });
  };

  const closeMenu = () => {
    if (!nav || !navToggle) return;
    nav.classList.remove('is-open');
    navToggle.setAttribute('aria-expanded', 'false');
    header.classList.remove('menu-open');
  };

  const openMenu = () => {
    if (!nav || !navToggle) return;
    nav.classList.add('is-open');
    navToggle.setAttribute('aria-expanded', 'true');
    header.classList.add('menu-open');
  };

  const toggleMenu = () => {
    if (!nav || !navToggle) return;
    if (nav.classList.contains('is-open')) {
      closeMenu();
      closeDropdowns();
    } else {
      closeDropdowns();
      openMenu();
    }
  };

  const markCurrentNav = () => {
    const path = window.location.pathname || '/';
    const links = nav ? Array.from(nav.querySelectorAll('a[href]')) : [];

    links.forEach((link) => {
      const href = link.getAttribute('href');
      if (!href) return;

      const exactMatch = path === href || (href !== '/' && path === href.replace(/index\.html$/, ''));
      const sectionMatch = href !== '/' && href.endsWith('/') && path.startsWith(href);

      if (exactMatch || sectionMatch) {
        link.classList.add('is-current');
        if (exactMatch) link.setAttribute('aria-current', 'page');
      }
    });

    const toolsButton = nav ? nav.querySelector('[data-nav-section="tools"]') : null;
    const guidesButton = nav ? nav.querySelector('[data-nav-section="guides"]') : null;

    if (toolsButton && path.startsWith('/tools/')) toolsButton.classList.add('is-current');
    if (guidesButton && path.startsWith('/guia/')) guidesButton.classList.add('is-current');
  };

  if (window.matchMedia('(max-width: 860px)').matches) {
    closeMenu();
  }

  markCurrentNav();

  if (nav && navToggle) {
    navToggle.addEventListener('click', (e) => {
      e.preventDefault();
      toggleMenu();
    });

    nav.addEventListener('click', (e) => {
      const link = e.target.closest('a');
      if (link && nav.classList.contains('is-open')) {
        closeMenu();
        closeDropdowns();
      }
    });

    document.addEventListener('click', (e) => {
      if (!header.contains(e.target)) {
        closeMenu();
        closeDropdowns();
      }
    });

    document.addEventListener('keydown', (e) => {
      if (e.key !== 'Escape') return;
      closeMenu();
      closeDropdowns();
    });

    window.addEventListener('resize', () => {
      if (window.matchMedia('(min-width: 861px)').matches) {
        closeMenu();
        closeDropdowns();
      }
    });
  }

  dropdowns.forEach((dropdown) => {
    const toggle = dropdown.querySelector('.nav-dropdown');
    if (!toggle) return;

    toggle.addEventListener('click', (e) => {
      e.preventDefault();
      const isOpen = dropdown.classList.contains('open');
      if (isOpen) {
        closeDropdowns();
        return;
      }

      closeDropdowns(dropdown);
      dropdown.classList.add('open');
      toggle.setAttribute('aria-expanded', 'true');
    });
  });

  let lastY = window.scrollY || 0;
  let ticking = false;
  const threshold = 8;
  const minShowY = 40;
  const minDeltaToToggle = 14;

  const onScroll = () => {
    const y = window.scrollY || 0;
    const delta = y - lastY;

    if (header.classList.contains('menu-open')) {
      header.classList.remove('is-hidden');
      lastY = y;
      return;
    }

    if (y <= minShowY) {
      header.classList.remove('is-hidden');
      lastY = y;
      return;
    }

    if (Math.abs(delta) < threshold) return;

    if (delta > minDeltaToToggle) {
      header.classList.add('is-hidden');
      closeDropdowns();
    } else if (delta < -minDeltaToToggle) {
      header.classList.remove('is-hidden');
    }

    lastY = y;
  };

  window.addEventListener('scroll', () => {
    if (!ticking) {
      window.requestAnimationFrame(() => {
        onScroll();
        ticking = false;
      });
      ticking = true;
    }
  }, { passive: true });
})();
